catalog_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {
    if (isLoading || newValue == '') {
        return;
    }

    // Get the values from the form
    var startPoint = g_form.getValue('starting_point');
    var endPoint = newValue; // This is the ending_point value
    var tickets = g_form.getValue('no_of_ticket') || 1;

    // Call your backend calculation logic via GlideAjax
    var ga = new GlideAjax('MetroFareCalculator'); // Replace with your Script Include name
    ga.addParam('sysparm_name', 'calculateFare'); // Replace with your function name
    ga.addParam('sysparm_start', startPoint);
    ga.addParam('sysparm_end', endPoint);
    ga.addParam('sysparm_tickets', tickets);

    ga.getXMLAnswer(function(response) {
        // Populate the Total Fare field dynamically on the screen
        g_form.setValue('total_fare', response);
    });
}
